const fuentes = [
  () => $('AI Agent consultas').first().json?.output,
  () => $('Respuestas sin consulta').first().json?.output,
  () => $('Msg Confirmado1').first().json?.respuesta,
  () => $('Msg Ocupado1').first().json?.respuesta,
  () => $('Msg Pedir Fecha1').first().json?.respuesta,
];

let respuesta = '';
for (const fn of fuentes) {
  try {
    const val = fn();
    if (val && val.trim() !== '') {
      respuesta = val;
      break;
    }
  } catch(e) {}
}

return [{ json: { respuesta } }];

